import React, { useState, useMemo } from "react";
import EditorialFlow from "./EditorialFlow";

interface MediaLibraryProps {
  onBack?: () => void;
}

const MediaLibrary: React.FC<MediaLibraryProps> = ({ onBack }) => {
  const [view, setView] = useState<'library' | 'flow'>('library');

  return (
    <div className="container mx-auto px-4 py-4 h-full flex flex-col">
      {/* Bouton Retour */}
      {onBack && (
        <button
          onClick={onBack}
          className="mb-4 px-4 py-2 bg-gray-200 dark:bg-gray-700 hover:bg-gray-300 dark:hover:bg-gray-600 rounded-lg text-sm transition-colors flex items-center gap-2"
        >
          <i className="fas fa-arrow-left"></i>
          Retour aux Documents
        </button>
      )}

      {/* En-tête */}
      <div className="bg-white dark:bg-gray-800 rounded-lg shadow mb-4 p-4">
        <div className="flex flex-col sm:flex-row sm:justify-between sm:items-center gap-4">
          <h1 className="text-2xl font-bold text-gray-900 dark:text-white flex items-center">
            <i className="fas fa-folder-open mr-3 text-purple-600"></i>
            Médiathèque BCM-GEST
          </h1>
          
          {/* Toggle Vue */}
          <div className="flex gap-2">
            <button
              onClick={() => setView('library')}
              className={`px-4 py-2 rounded-lg text-sm font-medium transition-all duration-200 flex items-center gap-2 ${
                view === 'library'
                  ? 'bg-purple-600 text-white shadow-lg'
                  : 'bg-gray-200 dark:bg-gray-700 text-gray-700 dark:text-gray-300 hover:bg-gray-300 dark:hover:bg-gray-600'
              }`}
            >
              <i className="fas fa-th-large"></i>
              Médiathèque
            </button>
            <button
              onClick={() => setView('flow')}
              className={`px-4 py-2 rounded-lg text-sm font-medium transition-all duration-200 flex items-center gap-2 ${
                view === 'flow'
                  ? 'bg-purple-600 text-white shadow-lg'
                  : 'bg-gray-200 dark:bg-gray-700 text-gray-700 dark:text-gray-300 hover:bg-gray-300 dark:hover:bg-gray-600'
              }`}
            >
              <i className="fas fa-project-diagram"></i>
              Flux Éditorial
            </button>
          </div>
        </div>
      </div>

      {/* Contenu */}
      {view === 'library' ? (
        <MediaLibraryGrid />
      ) : (
        <EditorialFlow />
      )}
    </div>
  );
};

// ✅ COMPOSANT GRILLE AVEC FILTRES
const MediaLibraryGrid: React.FC = () => {
  const [searchTerm, setSearchTerm] = useState("");
  const [typeFilter, setTypeFilter] = useState("Tous");
  const [dateFilter, setDateFilter] = useState("Tous");
  const [statusFilter, setStatusFilter] = useState("Tous");

  // Fichiers de démo
  const demoFiles = [
    { id: 1, name: "audio_001.mp3", type: "audio", date: "2025-01-15", size: "5.2 MB", status: "importé" },
    { id: 2, name: "audio_002.mp3", type: "audio", date: "2025-01-15", size: "3.8 MB", status: "transcrit" },
    { id: 3, name: "scan_chapitre1.pdf", type: "pdf", date: "2025-01-14", size: "2.1 MB", status: "importé" },
    { id: 4, name: "photo_001.jpg", type: "image", date: "2025-01-14", size: "1.5 MB", status: "importé" },
    { id: 5, name: "interview_003.mp3", type: "audio", date: "2025-01-13", size: "8.4 MB", status: "transcrit" },
    { id: 6, name: "document_002.pdf", type: "pdf", date: "2025-01-13", size: "4.2 MB", status: "projet livre" },
  ];

  // ✅ FILTRAGE
  const filteredFiles = useMemo(() => {
    return demoFiles.filter((file) => {
      const matchesSearch = file.name.toLowerCase().includes(searchTerm.toLowerCase());
      const matchesType = typeFilter === "Tous" || file.type === typeFilter;
      const matchesStatus = statusFilter === "Tous" || file.status === statusFilter;
      
      let matchesDate = true;
      if (dateFilter === "today") {
        matchesDate = file.date === new Date().toISOString().split('T')[0];
      } else if (dateFilter === "week") {
        const weekAgo = new Date();
        weekAgo.setDate(weekAgo.getDate() - 7);
        matchesDate = new Date(file.date) >= weekAgo;
      } else if (dateFilter === "month") {
        const monthAgo = new Date();
        monthAgo.setMonth(monthAgo.getMonth() - 1);
        matchesDate = new Date(file.date) >= monthAgo;
      }
      
      return matchesSearch && matchesType && matchesStatus && matchesDate;
    });
  }, [searchTerm, typeFilter, dateFilter, statusFilter]);

  const getFileIcon = (type: string) => {
    switch (type) {
      case 'audio': return 'fas fa-music text-blue-500';
      case 'pdf': return 'fas fa-file-pdf text-red-500';
      case 'image': return 'fas fa-file-image text-green-500';
      default: return 'fas fa-file text-gray-500';
    }
  };

  return (
    <div className="bg-white dark:bg-gray-800 rounded-lg shadow flex-1 overflow-hidden border border-gray-200 dark:border-gray-700">
      {/* ✅ BARRE DE FILTRES COMPLÈTE */}
      <div className="bg-gray-50 dark:bg-gray-700/50 px-6 py-4 border-b border-gray-200 dark:border-gray-700">
        <div className="flex flex-col lg:flex-row gap-4">
          {/* Recherche */}
          <div className="flex-1">
            <div className="relative">
              <input
                type="text"
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                className="w-full pl-10 pr-4 py-2 text-base border border-gray-300 dark:border-gray-700 rounded-md focus:outline-none focus:ring-2 focus:ring-purple-500 focus:border-transparent dark:bg-gray-700 dark:text-white"
                placeholder="Rechercher un fichier..."
              />
              <i className="fas fa-search absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400"></i>
            </div>
          </div>
          
          {/* Filtres */}
          <div className="flex gap-3 flex-wrap">
            <select
              value={typeFilter}
              onChange={(e) => setTypeFilter(e.target.value)}
              className="px-4 py-2 border border-gray-300 dark:border-gray-700 rounded-md focus:outline-none focus:ring-2 focus:ring-purple-500 dark:bg-gray-700 dark:text-white"
            >
              <option value="Tous">Tous les types</option>
              <option value="audio">Audio</option>
              <option value="pdf">PDF</option>
              <option value="image">Image</option>
            </select>
            
            <select
              value={statusFilter}
              onChange={(e) => setStatusFilter(e.target.value)}
              className="px-4 py-2 border border-gray-300 dark:border-gray-700 rounded-md focus:outline-none focus:ring-2 focus:ring-purple-500 dark:bg-gray-700 dark:text-white"
            >
              <option value="Tous">Tous les statuts</option>
              <option value="importé">Importé</option>
              <option value="transcrit">Transcrit</option>
              <option value="projet livre">Projet de livre</option>
              <option value="relecture 1">Relecture 1</option>
              <option value="relecture 2">Relecture 2</option>
            </select>
            
            <select
              value={dateFilter}
              onChange={(e) => setDateFilter(e.target.value)}
              className="px-4 py-2 border border-gray-300 dark:border-gray-700 rounded-md focus:outline-none focus:ring-2 focus:ring-purple-500 dark:bg-gray-700 dark:text-white"
            >
              <option value="Tous">Toutes les dates</option>
              <option value="today">Aujourd'hui</option>
              <option value="week">Cette semaine</option>
              <option value="month">Ce mois</option>
            </select>
            
            <button className="px-4 py-2 bg-purple-600 hover:bg-purple-700 text-white rounded-md transition-all duration-200 flex items-center gap-2 hover:shadow-lg">
              <i className="fas fa-upload"></i>
              Importer
            </button>
            
            {(searchTerm || typeFilter !== "Tous" || dateFilter !== "Tous" || statusFilter !== "Tous") && (
              <button
                onClick={() => {
                  setSearchTerm("");
                  setTypeFilter("Tous");
                  setDateFilter("Tous");
                  setStatusFilter("Tous");
                }}
                className="px-4 py-2 bg-gray-200 dark:bg-gray-600 hover:bg-gray-300 dark:hover:bg-gray-500 text-gray-700 dark:text-gray-300 rounded-md transition-all duration-200"
              >
                <i className="fas fa-times"></i>
              </button>
            )}
          </div>
        </div>
        
        {/* Résultats */}
        <div className="mt-3 text-sm text-gray-600 dark:text-gray-400">
          <strong>{filteredFiles.length}</strong> fichier{filteredFiles.length > 1 ? 's' : ''} trouvé{filteredFiles.length > 1 ? 's' : ''} sur <strong>{demoFiles.length}</strong>
        </div>
      </div>

      {/* Grille de fichiers */}
      <div className="p-6 overflow-y-auto" style={{ maxHeight: 'calc(100vh - 350px)' }}>
        {filteredFiles.length === 0 ? (
          <div className="text-center py-16">
            <i className="fas fa-search text-4xl text-gray-400 mb-4"></i>
            <p className="text-gray-600 dark:text-gray-400">Aucun fichier ne correspond aux filtres</p>
          </div>
        ) : (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4">
            {filteredFiles.map((file) => (
              <div
                key={file.id}
                className="bg-white dark:bg-gray-700 rounded-lg border border-gray-200 dark:border-gray-600 p-4 hover:shadow-lg transition-all duration-200 cursor-pointer group"
              >
                <div className="flex items-start justify-between mb-3">
                  <div className="flex items-center gap-3">
                    <div className="w-12 h-12 bg-gray-100 dark:bg-gray-600 rounded-lg flex items-center justify-center">
                      <i className={`${getFileIcon(file.type)} text-2xl`}></i>
                    </div>
                    <div>
                      <h3 className="font-medium text-gray-900 dark:text-white text-sm line-clamp-1">
                        {file.name}
                      </h3>
                      <p className="text-xs text-gray-500 dark:text-gray-400">
                        {file.date} • {file.size}
                      </p>
                    </div>
                  </div>
                  <button className="opacity-0 group-hover:opacity-100 transition-opacity p-1 hover:bg-gray-100 dark:hover:bg-gray-600 rounded">
                    <i className="fas fa-ellipsis-v text-gray-400"></i>
                  </button>
                </div>
                
                <div className="flex gap-2">
                  <span className="px-2 py-1 text-xs bg-purple-100 dark:bg-purple-900/30 text-purple-800 dark:text-purple-200 rounded-full capitalize">
                    {file.type}
                  </span>
                  <span className="px-2 py-1 text-xs bg-green-100 dark:bg-green-900/30 text-green-800 dark:text-green-200 rounded-full">
                    {file.status}
                  </span>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

export default MediaLibrary;
